import { Link } from "react-router-dom";

import React, {
useEffect,
useState
}

from "react";

import { getAllVariants }
from "../services/ApiService";

import cretaImage
from "../assets/creta.jpg";

import venueImage
from "../assets/venue.jpg";

import i20Image
from "../assets/i20.jpg";

function Home() {


const [variants, setVariants] =
    useState([]);

useEffect(() => {

    loadVariants();

}, []);

const loadVariants = async () => {

    try {

        const response =
            await getAllVariants();

        setVariants(
            response.data
        );

    } catch (error) {

        console.log(error);
    }
};

const getCarImage =
    (variantName) => {

    if (variantName === "Creta") {

        return cretaImage;
    }

    if (variantName === "Venue") {

        return venueImage;
    }

    if (variantName === "i20") {

        return i20Image;
    }
};

return (

    <div
        style={{
            padding: "20px"
        }}
    >

        <h1>

            All Car Variants

        </h1>

        <div
            style={{

                display: "flex",

                flexWrap: "wrap",

                justifyContent:
                    "center",

                gap: "20px",

                marginTop: "30px"
            }}
        >

            {
                variants.map(
                    (variant) => (

                    <div
                        key={variant.id}

                        style={{

                            border:
                                "1px solid lightgray",

                            borderRadius:
                                "10px",

                            padding:
                                "20px",

                            width:
                                "300px",

                            boxShadow:
                                "0px 0px 10px lightgray",

                            backgroundColor:
                                "white"
                        }}
                    >

                        <img
                            src={
                                getCarImage(
                                    variant.variantName
                                )
                            }

                            alt="car"

                            style={{
                                width: "100%",

                                height: "200px",

                                objectFit:
                                    "cover",

                                borderRadius:
                                    "10px"
                            }}
                        />

                        <h2>

                            {
                                variant
                                    .variantName
                            }

                        </h2>

                        <p>

                            <b>
                                Company :
                            </b>

                            {" "}

                            {
                                variant
                                .carCompany
                                .companyName
                            }

                        </p>

                        <p>

                            <b>
                                Fuel Type :
                            </b>

                            {" "}

                            {
                                variant
                                    .fuelType
                            }

                        </p>

                        <p>

                            <b>
                                Price Per Day :
                            </b>

                            {" "}

                            ₹ {
                                variant
                                .pricePerDay
                            }

                        </p>

                        <p>

                            <b>
                                Available Cars :
                            </b>

                            {" "}

                            {
                                variant
                                .availableCars
                            }

                        </p>

                        {
                            variant.availableCars > 0 ? (

                                <Link
                                    to={
                                        `/booking/${variant.id}`
                                    }
                                >

                                    <button
                                        style={{

                                            padding:
                                                "10px",

                                            backgroundColor:
                                                "black",

                                            color:
                                                "white",

                                            border:
                                                "none",

                                            borderRadius:
                                                "5px",

                                            cursor:
                                                "pointer",

                                            width:
                                                "100%"
                                        }}
                                    >

                                        Book Now

                                    </button>

                                </Link>

                            ) : (

                                <button
                                    disabled

                                    style={{

                                        padding:
                                            "10px",

                                        backgroundColor:
                                            "gray",

                                        color:
                                            "white",

                                        border:
                                            "none",

                                        borderRadius:
                                            "5px",

                                        width:
                                            "100%",

                                        opacity:
                                            "0.6",

                                        cursor:
                                            "not-allowed"
                                    }}
                                >

                                    Already Booked

                                </button>

                            )
                        }

                    </div>
                ))
            }

        </div>

    </div>
);


}

export default Home;
